import pandas as pd

results = []
for i in range(4, 9):
    if f'data_{i}' in env:
        results.extend(env[f'data_{i}'])

df = pd.DataFrame(results)
df = df.drop_duplicates(subset=['Symbol'])
df = df.sort_values('days', ascending=False).head(5)

company_map = env['company_map']
def get_company_name(desc):
    for verb in [" offers ", " is ", " provides ", " aims ", " seeks ", " was ", " specializes ", " operates "]:
        if verb in desc:
            return desc.split(verb)[0].strip()
    return desc

df['Company Name'] = df['Symbol'].map(lambda x: get_company_name(company_map[x]))
print(df)

answer = df['Company Name'].tolist()
env['_answer'] = answer
print("Answer:", answer)

